import hre from "hardhat";

// Colour codes for terminal prints
const RESET = "\x1b[0m";
const GREEN = "\x1b[32m";

function delay(ms: number) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function main() {
  const constructorArgs = ["Hello, Hardhat!"];
  const contract = await hre.ethers.deployContract("Greeter", constructorArgs);

  await contract.waitForDeployment();
  const contractAddress = await contract.getAddress();

  console.log("Greeter deployed to: " + `${GREEN}${contractAddress}${RESET}\n`);

  console.log(
    "Waiting 30 seconds before beginning the contract verification to allow the block explorer to index the contract...\n",
  );
  await delay(30000); // Wait for 30 seconds before verifying the contract

  await hre.run("verify:verify", {
    address: contractAddress,
    constructorArguments: constructorArgs,
  });

  // Uncomment if you want to enable the `tenderly` extension
  // await hre.tenderly.verify({
  //   name: "Greeter",
  //   address: contractAddress,
  // });
}

main().catch((error) => {
  console.error(error);
  process.exitCode = 1;
});

import { expect } from 'chai';

import { Contract } from 'ethers';
import { deploy } from '@balancer-labs/v2-helpers/src/contract';
import { MAX_INT256, MIN_INT256 } from '@balancer-labs/v2-helpers/src/constants';
import { sharedBeforeEach } from '@balancer-labs/v2-common/sharedBeforeEach';

describe('Math', () => {
  let lib: Contract;

  sharedBeforeEach('deploy lib', async () => {
    lib = await deploy('MathMock', { args: [] });
  });

  it('handles zero', async () => {
    expect(await lib.abs(0)).to.equal(0);
  });

  it('handles positive values', async () => {
    expect(await lib.abs(42)).to.equal(42);
  });

  it('handles large positive values', async () => {
    expect(await lib.abs(MAX_INT256)).to.equal(MAX_INT256);
  });

  it('handles negative values', async () => {
    expect(await lib.abs(-3)).to.equal(3);
  });

  it('handles large negative values', async () => {
    expect(await lib.abs(MIN_INT256)).to.equal(MIN_INT256.mul(-1));
  });
});

import { ethers, BigNumberish } from "ethers";
import { buildContractCall, MetaTransaction, SafeTransaction } from "./execution";
import { MultiSend } from "../../typechain-types";

const encodeMetaTransaction = (tx: MetaTransaction): string => {
    const data = ethers.getBytes(tx.data);
    const encoded = ethers.solidityPacked(
        ["uint8", "address", "uint256", "uint256", "bytes"],
        [tx.operation, tx.to, tx.value, data.length, data],
    );
    return encoded.slice(2);
};

export const encodeMultiSend = (txs: MetaTransaction[]): string => {
    return "0x" + txs.map((tx) => encodeMetaTransaction(tx)).join("");
};

export const buildMultiSendSafeTx = async (
    multiSend: MultiSend,
    txs: MetaTransaction[],
    nonce: BigNumberish,
    overrides?: Partial<SafeTransaction>,
): Promise<SafeTransaction> => {
    return buildContractCall(multiSend, "multiSend", [encodeMultiSend(txs)], nonce, true, overrides);
};

import { ethers } from 'ethers';
import { EIP712Signer, Wallet } from 'zksync-ethers';
import { TransactionLike } from 'zksync-ethers/build/types';
import { serializeEip712 } from 'zksync-ethers/build/utils';

export class HardhatZksyncEIP712Signer extends EIP712Signer {
    private readonly accountWallet: Wallet;

    constructor(wallet: Wallet, chainId: number | Promise<number>) {
        super(wallet, chainId);
        this.accountWallet = wallet;
    }

    public async signMessage(message: string | Uint8Array): Promise<string> {
        return this.accountWallet.signMessage(message);
    }

    public async signTransaction(_transaction: TransactionLike): Promise<string> {
        _transaction.customData = _transaction.customData || {};
        _transaction.customData.customSignature = await this.sign(_transaction);

        return serializeEip712(_transaction);
    }

    public async signTypedData(
        _domain: ethers.TypedDataDomain,
        _types: Record<string, ethers.TypedDataField[]>,
        _value: Record<string, any>,
    ): Promise<string> {
        return this.accountWallet.signTypedData(_domain, _types, _value);
    }
}

function numberWithCommas(x) {
  return x.toString().replace(/\B(?<!\.\d*)(?=(\d{3})+(?!\d))/g, ",")
}

async function getPriceUSD(address, ethers) {
  const priceFeed = new ethers.Contract(
    address,
    [
      {
        inputs: [],
        name: "decimals",
        outputs: [{ internalType: "uint8", name: "", type: "uint8" }],
        stateMutability: "view",
        type: "function",
      },
      {
        inputs: [],
        name: "latestRoundData",
        outputs: [
          { internalType: "uint80", name: "roundId", type: "uint80" },
          { internalType: "int256", name: "answer", type: "int256" },
          { internalType: "uint256", name: "startedAt", type: "uint256" },
          { internalType: "uint256", name: "updatedAt", type: "uint256" },
          { internalType: "uint80", name: "answeredInRound", type: "uint80" },
        ],
        stateMutability: "view",
        type: "function",
      },
    ],
    ethers.provider
  )
  const decimals = await priceFeed.decimals()
  const latestRound = await priceFeed.latestRoundData()
  return ethers.utils.formatUnits(latestRound.answer, decimals)
}

module.exports = {
  numberWithCommas,
  getPriceUSD,
}

