import chalk from "chalk";

import { UiState } from "../types";

import { pathFromCwd } from "./cwd-relative-path";

export function calculateDeployingModulePanel(state: UiState): string {
  let deployingMessage = `Hardhat Ignition 🚀

`;

  if (state.isResumed === true) {
    deployingMessage += `${chalk.bold(
      `Resuming existing deployment from ${pathFromCwd(state.deploymentDir!)}`
    )}

`;
  }

  deployingMessage += `${chalk.bold(
    `Deploying [ ${state.moduleName ?? "unknown"} ]${_calculateStrategySuffix(
      state
    )}`
  )}
`;

  if (state.warnings.length > 0) {
    deployingMessage += `\n${chalk.yellow(
      "Warning - previously executed futures are not in the module:"
    )}\n`;

    deployingMessage += state.warnings
      .map((futureId) => chalk.yellow(` - ${futureId}`))
      .join("\n");

    deployingMessage += "\n";
  }

  return deployingMessage;
}

function _calculateStrategySuffix(state: UiState) {
  if (state.strategy === "basic") {
    return "";
  }

  return ` with strategy ${state.strategy ?? "unknown"}`;
}

import { ISolFileEntry, TextDocument } from "@common/types";
import { URI } from "vscode-uri";
import { Project } from "../frameworks/base/Project";
import { ServerState } from "../types";

export function getOpenDocumentsInProject(
  serverState: ServerState,
  project: Project
): TextDocument[] {
  const openSolFilesInProj = Object.values(serverState.solFileIndex).filter(
    (solfile) => solfile.project.basePath === project.basePath
  );

  const openDocuments = openSolFilesInProj
    .map((solFile) => lookupDocForSolFileEntry(serverState, solFile))
    .filter((doc): doc is TextDocument => doc !== undefined);

  return openDocuments;
}

function lookupDocForSolFileEntry(
  serverState: ServerState,
  solFile: ISolFileEntry
): TextDocument | undefined {
  const convertedUri = URI.file(solFile.uri).toString();

  return serverState.documents.get(convertedUri);
}

import chalk from 'chalk';

function logWarning(title: string, lines: string[] = []): void {
    log('Warning', title, lines);
}

function indent(text: string, amount: number, amount0 = amount): string {
    return text.replace(/^/gm, (_, i) => ' '.repeat(i === 0 ? amount0 : amount));
}

let silenced = false;

function log(prefix: string, title: string, lines: string[]): void {
    if (silenced) {
        return;
    }

    const parts = [`${chalk.yellow.bold(`${prefix}:`)} ${title}\n`];

    if (lines.length > 0) {
        parts.push(lines.map((l) => `${indent(l, 4)}\n`).join(''));
    }

    console.error(parts.join('\n'));
}

export function silenceWarnings(): void {
    logWarning(`All subsequent Upgrades warnings will be silenced.`, [
        `Make sure you have manually checked all uses of unsafe flags.`,
    ]);
    silenced = true;
}

import { CodeActionParams, CodeAction } from "vscode-languageserver/node";
import { ServerState } from "../../types";
import { FAILED_PRECONDITION, OK } from "../../telemetry/TelemetryStatus";
import { resolveQuickFixes } from "./QuickFixResolver";

export function onCodeAction(serverState: ServerState) {
  return (params: CodeActionParams): CodeAction[] => {
    const { documents, logger } = serverState;

    logger.trace("onCodeAction");

    return (
      serverState.telemetry.trackTimingSync("onCodeAction", () => {
        const document = documents.get(params.textDocument.uri);

        if (!document) {
          return { status: FAILED_PRECONDITION, result: [] };
        }

        const quickfixes = resolveQuickFixes(
          serverState,
          params.textDocument.uri,
          document,
          params.context.diagnostics
        );

        return { status: OK, result: quickfixes };
      }) ?? []
    );
  };
}

import { ISolFileEntry } from "@common/types";
import { TextDocument } from "vscode-languageserver-textdocument";
import { addFrameworkTag } from "../telemetry/tags";
import { ServerState } from "../types";
import { FAILED_PRECONDITION, OK } from "../telemetry/TelemetryStatus";
import { lookupEntryForUri } from "./lookupEntryForUri";

export function onCommand<T>(
  serverState: ServerState,
  commandName: string,
  uri: string,
  action: (documentAnalyzer: ISolFileEntry, document: TextDocument) => T
) {
  const { logger, telemetry } = serverState;

  logger.trace(commandName);

  return telemetry.trackTimingSync(commandName, () => {
    const { found, errorMessage, documentAnalyzer, document } =
      lookupEntryForUri(serverState, uri);

    if (!found || !documentAnalyzer || !document) {
      if (errorMessage !== undefined) {
        logger.trace(errorMessage);
      }

      return { status: FAILED_PRECONDITION, result: null };
    }

    addFrameworkTag(documentAnalyzer.project);

    return {
      status: OK,
      result: action(documentAnalyzer, document),
    };
  });
}

import type { DeploymentState } from "../../execution/types/deployment-state.js";
import type {
  CallExecutionState,
  DeploymentExecutionState,
  SendDataExecutionState,
  StaticCallExecutionState,
} from "../../execution/types/execution-state.js";

import { ExecutionSateType } from "../../execution/types/execution-state.js";

export function getNetworkExecutionStates(
  deploymentState: DeploymentState,
): Array<
  | DeploymentExecutionState
  | CallExecutionState
  | SendDataExecutionState
  | StaticCallExecutionState
> {
  const exStates: Array<
    | DeploymentExecutionState
    | CallExecutionState
    | SendDataExecutionState
    | StaticCallExecutionState
  > = [];

  for (const exState of Object.values(deploymentState.executionStates)) {
    if (
      exState.type === ExecutionSateType.DEPLOYMENT_EXECUTION_STATE ||
      exState.type === ExecutionSateType.CALL_EXECUTION_STATE ||
      exState.type === ExecutionSateType.SEND_DATA_EXECUTION_STATE ||
      exState.type === ExecutionSateType.STATIC_CALL_EXECUTION_STATE
    ) {
      exStates.push(exState);
    }
  }

  return exStates;
}

import { MinimalInterpreterStep } from "hardhat/internal/hardhat-network/provider/vm/types";

import { AwaitedItem, Item } from "../types";
